class AmateurPressAssociation:
    def __init__(self):
        self.members = {}

    def add_member(self, name, age, location):
        self.members[name] = {'age': age, 'location': location}

    def get_member_count(self):
        return len(self.members)

    def list_members(self):
        for name, details in self.members.items():
            print(f"Name: {name}, Age: {details['age']}, Location: {details['location']}")

# Example usage
apa = AmateurPressAssociation()
apa.add_member("Leland Hawes", 72, "Tampa, Florida")
apa.add_member("Jane Doe", 65, "Chicago, Illinois")
print(f"Total members: {apa.get_member_count()}")
apa.list_members()
